/* ===== AUDIO (Web Audio API — no files needed) ===== */
let actx=null, musicGain=null, sfxGain=null, musicPlaying=false, musicTimer=null;

function initAudio() {
  if (actx) return;
  const AC = window.AudioContext || window.webkitAudioContext;
  if (!AC) return;
  actx = new AC();
  musicGain = actx.createGain(); musicGain.gain.value = 0.20; musicGain.connect(actx.destination);
  sfxGain   = actx.createGain(); sfxGain.gain.value   = 0.55; sfxGain.connect(actx.destination);
  startMusic();
}

function startMusic() {
  if (musicPlaying || !actx) return;
  musicPlaying = true;
  const bpm=138, beat=60/bpm, loopLen=beat*16;
  const bassNotes=[55,55,49,55, 55,52,55,52];
  const arpNotes =[330,440,550,660,550,440,330,220, 370,494,622,740,622,494,370,247];

  function note(type,freq,when,dur,vol=.3){
    const o=actx.createOscillator(), g=actx.createGain();
    o.type=type; o.frequency.value=freq;
    o.connect(g); g.connect(musicGain);
    g.gain.setValueAtTime(vol,when);
    g.gain.exponentialRampToValueAtTime(0.001,when+dur);
    o.start(when); o.stop(when+dur+.01);
  }
  function noise(when,dur,vol=.25,lo=false){
    const buf=actx.createBuffer(1,actx.sampleRate*dur,actx.sampleRate);
    const d=buf.getChannelData(0); for(let i=0;i<d.length;i++) d[i]=Math.random()*2-1;
    const src=actx.createBufferSource();
    const filt=actx.createBiquadFilter(); filt.type=lo?'lowpass':'highpass'; filt.frequency.value=lo?600:7000;
    const g=actx.createGain();
    src.buffer=buf; src.connect(filt); filt.connect(g); g.connect(musicGain);
    g.gain.setValueAtTime(vol,when); g.gain.exponentialRampToValueAtTime(0.001,when+dur);
    src.start(when);
  }
  function kick(when){
    const o=actx.createOscillator(),g=actx.createGain();
    o.type='sine'; o.frequency.setValueAtTime(180,when); o.frequency.exponentialRampToValueAtTime(40,when+.12);
    o.connect(g); g.connect(musicGain);
    g.gain.setValueAtTime(.55,when); g.gain.exponentialRampToValueAtTime(0.001,when+.18);
    o.start(when); o.stop(when+.2);
  }

  function scheduleLoop(t) {
    for(let i=0;i<8;i++)  note('sawtooth',bassNotes[i],t+i*beat*2,beat*1.8,.28);
    for(let i=0;i<16;i++) {
      note('square',arpNotes[i],t+i*beat,beat*.42,.16);
      noise(t+i*beat,.04,.1,false);
      if(i%4===0) kick(t+i*beat);
      if(i%4===2) noise(t+i*beat,.12,.22,false);
    }
  }

  let ls = actx.currentTime+.05;
  scheduleLoop(ls);
  function loop(){
    if(!musicPlaying) return;
    ls+=loopLen;
    scheduleLoop(ls);
    musicTimer=setTimeout(loop,(loopLen-.5)*1000);
  }
  musicTimer=setTimeout(loop,(loopLen-.5)*1000);
}

function stopMusic(){
  musicPlaying=false; clearTimeout(musicTimer);
}

function sfx(type){
  if(!actx) return;
  const t=actx.currentTime;
  if(type==='hit'){
    [0,90,180].forEach((d,i)=>{
      const o=actx.createOscillator(),g=actx.createGain();
      o.type='sine'; o.frequency.setValueAtTime(440+i*180,t+d/1000);
      o.frequency.exponentialRampToValueAtTime(880+i*200,t+d/1000+.12);
      o.connect(g); g.connect(sfxGain);
      g.gain.setValueAtTime(.3,t+d/1000); g.gain.exponentialRampToValueAtTime(.001,t+d/1000+.2);
      o.start(t+d/1000); o.stop(t+d/1000+.22);
    });
  } else if(type==='miss'){
    const o=actx.createOscillator(),g=actx.createGain();
    o.type='sawtooth'; o.frequency.setValueAtTime(220,t); o.frequency.exponentialRampToValueAtTime(80,t+.16);
    o.connect(g); g.connect(sfxGain);
    g.gain.setValueAtTime(.3,t); g.gain.exponentialRampToValueAtTime(.001,t+.2);
    o.start(t); o.stop(t+.22);
  } else if(type==='combo'){
    const freqs=[550,660,880,1100,1320]; const f=freqs[Math.min(combo-1,4)];
    const o=actx.createOscillator(),g=actx.createGain();
    o.type='triangle'; o.frequency.setValueAtTime(f,t); o.frequency.exponentialRampToValueAtTime(f*1.5,t+.22);
    o.connect(g); g.connect(sfxGain);
    g.gain.setValueAtTime(.4,t); g.gain.exponentialRampToValueAtTime(.001,t+.28);
    o.start(t); o.stop(t+.3);
  } else if(type==='bomb'){
    const buf=actx.createBuffer(1,actx.sampleRate*.45,actx.sampleRate);
    const d=buf.getChannelData(0); for(let i=0;i<d.length;i++) d[i]=(Math.random()*2-1)*(1-i/d.length);
    const src=actx.createBufferSource(),filt=actx.createBiquadFilter(),g=actx.createGain();
    filt.type='lowpass'; filt.frequency.value=600;
    src.buffer=buf; src.connect(filt); filt.connect(g); g.connect(sfxGain);
    g.gain.setValueAtTime(.65,t); g.gain.exponentialRampToValueAtTime(.001,t+.45);
    src.start(t);
  } else if(type==='frenzy'){
    [220,330,440,550,660,880].forEach((f,i)=>{
      setTimeout(()=>{
        if(!actx) return;
        const o=actx.createOscillator(),g=actx.createGain();
        o.type='triangle'; o.frequency.value=f;
        o.connect(g); g.connect(sfxGain);
        g.gain.setValueAtTime(.35,actx.currentTime); g.gain.exponentialRampToValueAtTime(.001,actx.currentTime+.3);
        o.start(actx.currentTime); o.stop(actx.currentTime+.32);
      },i*70);
    });
  } else if(type==='gameover'){
    [440,330,220,110].forEach((f,i)=>{
      setTimeout(()=>{
        if(!actx) return;
        const o=actx.createOscillator(),g=actx.createGain();
        o.type='sawtooth'; o.frequency.value=f;
        o.connect(g); g.connect(sfxGain);
        g.gain.setValueAtTime(.28,actx.currentTime); g.gain.exponentialRampToValueAtTime(.001,actx.currentTime+.4);
        o.start(actx.currentTime); o.stop(actx.currentTime+.45);
      },i*130);
    });
  }
}

