/* ===== LOADING SCREEN ===== */
let loadProgress=0;
const LOAD_MSGS=['Charging crystals...','Summoning gems...','Waking the moles...','Calibrating bombs...','Crystal Hunt loading...','AlphaGems ready!'];

function runLoadingScreen(){
  const bar=$('loading-bar');
  const txt=$('loading-text');
  let step=0;
  // Hard fallback: always show start screen after 4s no matter what
  const hardTimeout=setTimeout(()=>{
    const ls=$('loading-screen');
    if(ls&&!ls.classList.contains('gone')){
      ls.classList.add('fade-out');
      setTimeout(()=>{ ls.classList.add('gone'); ls.style.display='none'; $('start-screen').classList.remove('hidden'); },900);
    }
  },4000);
  const iv=setInterval(()=>{
    loadProgress=Math.min(100,loadProgress+Math.random()*14+5);
    if(bar) bar.style.width=loadProgress+'%';
    if(txt && step<LOAD_MSGS.length) txt.textContent=LOAD_MSGS[Math.floor(step)];
    step+=.8;
    if(loadProgress>=100){
      clearInterval(iv); clearTimeout(hardTimeout);
      if(txt) txt.textContent='Ready! ✨';
      setTimeout(()=>{
        const ls=$('loading-screen');
        if(ls) ls.classList.add('fade-out');
        setTimeout(()=>{
          if(ls){ ls.classList.add('gone'); ls.style.display='none'; }
          $('start-screen').classList.remove('hidden');
        },900);
      },500);
    }
  },120);
}

/* ===== LOADING CANVAS PARTICLES ===== */
function initLoadingParticles(){
  const cv=$('loading-particles');
  if(!cv) return;
  const ctx=cv.getContext('2d');
  let lp=[];

  function resize(){ cv.width=window.innerWidth; cv.height=window.innerHeight; }
  resize();
  window.addEventListener('resize',resize);

  for(let i=0;i<80;i++){
    lp.push({
      x:Math.random()*cv.width, y:Math.random()*cv.height,
      vx:(Math.random()-.5)*.6, vy:(Math.random()-.5)*.6,
      r:Math.random()*2+.5, life:Math.random(),
      col:['#a855f7','#6366f1','#06b6d4','#ec4899','#f59e0b','#fff'][Math.floor(Math.random()*6)]
    });
  }
  // gem shards floating
  for(let i=0;i<20;i++){
    lp.push({
      x:Math.random()*cv.width, y:Math.random()*cv.height,
      vx:(Math.random()-.5)*.4, vy:(Math.random()-.5)*.4-0.3,
      r:4+Math.random()*8, life:Math.random(), type:'shard',
      rot:Math.random()*Math.PI*2, rotSpd:(Math.random()-.5)*.03,
      col:'rgba(168,85,247,.5)'
    });
  }

  function drawShard(c,x,y,r,rot,col){
    c.save(); c.translate(x,y); c.rotate(rot);
    c.beginPath();
    const pts=[[0,-r],[r*.6,-r*.3],[r*.7,r*.35],[0,r],[-r*.7,r*.35],[-r*.6,-r*.3]];
    c.moveTo(pts[0][0],pts[0][1]); pts.forEach(pt=>c.lineTo(pt[0],pt[1])); c.closePath();
    c.fillStyle=col||'rgba(168,85,247,.5)'; c.strokeStyle='rgba(192,132,252,.6)'; c.lineWidth=1;
    c.fill(); c.stroke(); c.restore();
  }

  function tick(){
    if(!$('loading-screen')||$('loading-screen').classList.contains('gone')) return;
    ctx.clearRect(0,0,cv.width,cv.height);
    lp.forEach(p=>{
      p.x+=p.vx; p.y+=p.vy; p.life+=.008;
      if(p.x<0) p.x=cv.width; if(p.x>cv.width) p.x=0;
      if(p.y<0) p.y=cv.height; if(p.y>cv.height) p.y=0;
      const a=.3+.5*Math.abs(Math.sin(p.life*Math.PI));
      if(p.type==='shard'){
        p.rot+=p.rotSpd;
        ctx.globalAlpha=a*.7;
        drawShard(ctx,p.x,p.y,p.r,p.rot,p.col);
      } else {
        ctx.globalAlpha=a;
        ctx.fillStyle=p.col;
        ctx.shadowColor=p.col; ctx.shadowBlur=p.r*3;
        ctx.beginPath(); ctx.arc(p.x,p.y,p.r,0,Math.PI*2); ctx.fill();
        ctx.shadowBlur=0;
      }
      ctx.globalAlpha=1;
    });
    requestAnimationFrame(tick);
  }
  tick();
}

/* ===== BG CANVAS — enhanced nebula + stars + floating gems ===== */
const bgCanvas=$('bg-canvas');
const bgCtx=bgCanvas.getContext('2d');
let stars=[], nebulas=[], bgShards=[];

function resizeBg(){ bgCanvas.width=window.innerWidth; bgCanvas.height=window.innerHeight; }

function initBg(){
  resizeBg(); stars=[]; bgShards=[];
  const cols=['#a855f7','#6366f1','#06b6d4','#fff','#ec4899','#f59e0b','#818cf8'];
  for(let i=0;i<200;i++){
    stars.push({
      x:Math.random()*bgCanvas.width,
      y:Math.random()*bgCanvas.height,
      r:Math.random()*1.8+.2,
      sp:Math.random()*.5+.15,
      phase:Math.random()*Math.PI*2,
      col:cols[Math.floor(Math.random()*cols.length)]
    });
  }
  nebulas=[
    {x:.22,y:.25,r:.45,c:'rgba(168,85,247,.09)'},
    {x:.78,y:.75,r:.40,c:'rgba(99,102,241,.08)'},
    {x:.50,y:.50,r:.58,c:'rgba(6,182,212,.05)'},
    {x:.08,y:.82,r:.32,c:'rgba(236,72,153,.06)'},
    {x:.90,y:.15,r:.28,c:'rgba(245,158,11,.04)'},
  ];
  // slow floating gem shards in background
  for(let i=0;i<12;i++){
    bgShards.push({
      x:Math.random()*bgCanvas.width,
      y:Math.random()*bgCanvas.height,
      vy: -.15-Math.random()*.25,
      vx: (Math.random()-.5)*.1,
      r: 8+Math.random()*18,
      rot:Math.random()*Math.PI*2,
      rotSpd:(Math.random()-.5)*.006,
      alpha:Math.random()*.08+.03,
      phase:Math.random()*Math.PI*2
    });
  }
}

function drawBgShard(ctx,x,y,r){
  ctx.beginPath();
  const pts=[[0,-r],[r*.6,-r*.3],[r*.72,r*.35],[0,r],[-r*.72,r*.35],[-r*.6,-r*.3]];
  ctx.moveTo(x+pts[0][0],y+pts[0][1]);
  pts.forEach(p=>ctx.lineTo(x+p[0],y+p[1]));
  ctx.closePath(); ctx.fill(); ctx.stroke();
}

function drawBg(t){
  const W=bgCanvas.width, H=bgCanvas.height;
  const grd=bgCtx.createLinearGradient(0,0,0,H);
  grd.addColorStop(0,'#03030d'); grd.addColorStop(1,'#06061a');
  bgCtx.fillStyle=grd; bgCtx.fillRect(0,0,W,H);

  // nebulas
  nebulas.forEach(n=>{
    const g=bgCtx.createRadialGradient(n.x*W,n.y*H,0,n.x*W,n.y*H,n.r*Math.max(W,H));
    g.addColorStop(0,n.c); g.addColorStop(1,'transparent');
    bgCtx.fillStyle=g; bgCtx.fillRect(0,0,W,H);
  });

  // stars
  stars.forEach(s=>{
    const f=.5+.5*Math.sin(t*.001*s.sp+s.phase);
    bgCtx.globalAlpha=f*.85+.08;
    bgCtx.fillStyle=s.col;
    bgCtx.shadowColor=s.col; bgCtx.shadowBlur=s.r*2*f;
    bgCtx.beginPath(); bgCtx.arc(s.x,s.y,s.r*(1+.4*f),0,Math.PI*2); bgCtx.fill();
    if(s.r>1.3 && f>.8){
      bgCtx.globalAlpha=(f-.8)*3*.3;
      bgCtx.strokeStyle=s.col; bgCtx.lineWidth=.5;
      const len=s.r*5.5;
      bgCtx.beginPath();
      bgCtx.moveTo(s.x-len,s.y); bgCtx.lineTo(s.x+len,s.y);
      bgCtx.moveTo(s.x,s.y-len); bgCtx.lineTo(s.x,s.y+len);
      bgCtx.stroke();
    }
    bgCtx.shadowBlur=0;
  });
  bgCtx.globalAlpha=1;

  // floating background gem shards
  bgShards.forEach(s=>{
    s.x+=s.vx; s.y+=s.vy; s.rot+=s.rotSpd;
    if(s.y<-s.r*2){ s.y=H+s.r; s.x=Math.random()*W; }
    const pulse=s.alpha*(1+.4*Math.sin(t*.001+s.phase));
    bgCtx.save();
    bgCtx.translate(s.x,s.y); bgCtx.rotate(s.rot);
    bgCtx.globalAlpha=pulse;
    bgCtx.fillStyle='rgba(168,85,247,.5)';
    bgCtx.strokeStyle='rgba(192,132,252,.4)'; bgCtx.lineWidth=1;
    bgCtx.shadowColor='#a855f7'; bgCtx.shadowBlur=s.r*2;
    drawBgShard(bgCtx,0,0,s.r);
    bgCtx.shadowBlur=0; bgCtx.restore();
    bgCtx.globalAlpha=1;
  });
}

/* ===== PARTICLE CANVAS ===== */
const pCanvas=$('particle-canvas');
const pCtx=pCanvas.getContext('2d');
let particles=[];

function resizeP(){ pCanvas.width=window.innerWidth; pCanvas.height=window.innerHeight; }

function spawnGemBurst(x,y,cmb){
  const cols=['#a855f7','#c084fc','#f59e0b','#06b6d4','#ec4899','#fbbf24','#e879f9','white'];
  const N=24+cmb*6;
  for(let i=0;i<N;i++){
    const a=Math.random()*Math.PI*2, sp=3+Math.random()*8*Math.min(cmb,5);
    particles.push({ type:'dot', x, y, vx:Math.cos(a)*sp, vy:Math.sin(a)*sp-3, life:1, decay:.016+Math.random()*.026, r:3+Math.random()*6, col:cols[Math.floor(Math.random()*cols.length)], glow:true });
  }
  for(let i=0;i<14+cmb*2;i++){
    const a=Math.random()*Math.PI*2, sp=2+Math.random()*5;
    particles.push({ type:'shard', x, y, vx:Math.cos(a)*sp, vy:Math.sin(a)*sp-2, life:1, decay:.013+Math.random()*.016, r:5+Math.random()*10, rot:Math.random()*Math.PI*2, rotSpd:(Math.random()-.5)*.28 });
  }
  particles.push({ type:'ring', x, y, r:5, maxR:95, life:1, decay:.038 });
  if(cmb>=3) particles.push({ type:'ring', x, y, r:5, maxR:130, life:.8, decay:.03, col2:'rgba(245,158,11,.5)' });
  if(cmb===5) particles.push({ type:'ring', x, y, r:5, maxR:180, life:.7, decay:.022, col2:'rgba(236,72,153,.4)' });
}

function spawnMissBurst(x,y){
  for(let i=0;i<14;i++){
    const a=Math.random()*Math.PI*2;
    particles.push({ type:'dot', x, y, vx:Math.cos(a)*(1.5+Math.random()*4), vy:Math.sin(a)*(1.5+Math.random()*4), life:1, decay:.042, r:3+Math.random()*4, col:'#ef4444', glow:false });
  }
}

function spawnFrenzyBurst(){
  const cx=window.innerWidth/2, cy=window.innerHeight/2;
  const cols=['#a855f7','#f59e0b','#06b6d4','white','#ec4899'];
  for(let i=0;i<65;i++){
    const a=(i/65)*Math.PI*2+Math.random()*.5, sp=5+Math.random()*13;
    particles.push({ type:'dot', x:cx+Math.cos(a)*25, y:cy+Math.sin(a)*25, vx:Math.cos(a)*sp, vy:Math.sin(a)*sp-3, life:1, decay:.01, r:4+Math.random()*10, col:cols[Math.floor(Math.random()*cols.length)], glow:true });
  }
  for(let i=0;i<4;i++) particles.push({ type:'ring', x:cx, y:cy, r:5, maxR:200+i*60, life:1, decay:.022-i*.004, col2:`rgba(168,85,247,${.65-i*.12})` });
}

function drawShard(ctx,x,y,r){
  ctx.beginPath();
  const pts=[[0,-r],[r*.6,-r*.3],[r*.72,r*.35],[0,r],[-r*.72,r*.35],[-r*.6,-r*.3]];
  ctx.moveTo(x+pts[0][0],y+pts[0][1]); pts.forEach(p=>ctx.lineTo(x+p[0],y+p[1])); ctx.closePath();
  ctx.fill(); ctx.stroke();
}

function tickParticles(){
  pCtx.clearRect(0,0,pCanvas.width,pCanvas.height);
  particles=particles.filter(p=>p.life>0);
  particles.forEach(p=>{
    if(p.type!=='ring'){ p.x+=p.vx; p.y+=p.vy; p.vy+=.14; }
    p.life-=p.decay;
    const a=Math.max(0,p.life);
    if(p.type==='dot'){
      if(p.glow){ pCtx.shadowColor=p.col; pCtx.shadowBlur=p.r*2.5; }
      pCtx.globalAlpha=a; pCtx.fillStyle=p.col;
      pCtx.beginPath(); pCtx.arc(p.x,p.y,p.r,0,Math.PI*2); pCtx.fill();
      pCtx.shadowBlur=0;
    } else if(p.type==='shard'){
      p.rot+=p.rotSpd;
      pCtx.save(); pCtx.translate(p.x,p.y); pCtx.rotate(p.rot);
      pCtx.globalAlpha=a;
      pCtx.fillStyle='rgba(168,85,247,.65)'; pCtx.strokeStyle='rgba(192,132,252,.9)'; pCtx.lineWidth=1.2;
      pCtx.shadowColor='#a855f7'; pCtx.shadowBlur=p.r*1.5;
      drawShard(pCtx,0,0,p.r);
      pCtx.restore(); pCtx.shadowBlur=0;
    } else if(p.type==='ring'){
      p.r+=(p.maxR-p.r)*.09;
      pCtx.globalAlpha=a*.65;
      const rc=p.col2||'rgba(168,85,247,.7)';
      pCtx.strokeStyle=rc; pCtx.lineWidth=3;
      pCtx.shadowColor=rc; pCtx.shadowBlur=14;
      pCtx.beginPath(); pCtx.arc(p.x,p.y,p.r,0,Math.PI*2); pCtx.stroke();
      pCtx.shadowBlur=0;
    }
    pCtx.globalAlpha=1;
  });
}

/* ===== BOARD ===== */
function buildBoard(){
  const board=$('board'); board.innerHTML='';
  for(let i=0;i<9;i++){
    const h=document.createElement('div');
    h.className='hole'; h.id='h'+i;
    h.innerHTML=`<div class="hole-inner"><div class="hole-pit"></div><div class="hole-character" id="ch${i}"></div></div>`;
    h.addEventListener('click',()=>onHole(i));
    h.addEventListener('touchstart',e=>{e.preventDefault();onHole(i);},{passive:false});
    board.appendChild(h);
  }
}

/* ===== SPAWN ===== */
function randHole(ex=[]){
  let id,n=0; do{id=Math.floor(Math.random()*9);n++;}while(ex.includes(id)&&n<30); return id;
}

function showChar(id,type){
  const ch=$('ch'+id); ch.className='hole-character'; ch.innerHTML='';
  if(type==='gem'){
    const img=document.createElement('img'); img.src=GEM_SRC; img.draggable=false;
    ch.appendChild(img); ch.classList.add('gem-char'); gemId=id;
  } else if(type==='mole'){
    const img=document.createElement('img'); img.src=MOLE_SRC; img.draggable=false;
    ch.appendChild(img); ch.classList.add('mole-char'); moleId=id;
  } else if(type==='bomb'){
    const d=document.createElement('div'); d.className='bomb-icon'; d.textContent='💣';
    ch.appendChild(d); ch.classList.add('bomb-char'); bombId=id;
  }
  void ch.offsetWidth; ch.classList.add('show');
}

function hideChar(id){
  const ch=$('ch'+id); if(!ch||!ch.classList.contains('show')) return;
  ch.classList.remove('show'); ch.classList.add('hide');
  setTimeout(()=>{ch.classList.remove('hide');ch.innerHTML='';ch.className='hole-character';},240);
}

function schedGem(){
  clearTimeout(gemTimer); if(!gameActive) return;
  const spd=powerMode?cfg.gemSpeed*.44:cfg.gemSpeed;
  if(gemId!==null){hideChar(gemId);gemId=null;}
  const id=randHole([moleId,bombId].filter(x=>x!==null));
  showChar(id,'gem');
  gemTimer=setTimeout(()=>{if(gemId===id){hideChar(id);gemId=null;dropCombo();}schedGem();},spd+Math.random()*250);
}

function schedMole(){
  clearTimeout(moleTimer); if(!gameActive) return;
  if(moleId!==null){hideChar(moleId);moleId=null;}
  const id=randHole([gemId,bombId].filter(x=>x!==null));
  showChar(id,'mole');
  moleTimer=setTimeout(()=>{if(moleId===id){hideChar(id);moleId=null;}schedMole();},cfg.moleSpeed+Math.random()*300);
}

function schedBomb(){
  clearTimeout(bombTimer); if(!gameActive) return;
  if(Math.random()<cfg.bombChance){
    if(bombId!==null){hideChar(bombId);bombId=null;}
    const id=randHole([gemId,moleId].filter(x=>x!==null));
    showChar(id,'bomb');
    bombTimer=setTimeout(()=>{if(bombId===id){hideChar(id);bombId=null;}schedBomb();},cfg.bombSpeed);
  } else {
    bombTimer=setTimeout(schedBomb,650+Math.random()*440);
  }
}

/* ===== CLICK HANDLER ===== */
function onHole(id){
  if(!gameActive) return;
  initAudio();
  totalClicks++;
  const hole=$('h'+id);
  const rect=hole.getBoundingClientRect();
  const cx=rect.left+rect.width*.5, cy=rect.top+rect.height*.5;

  if(id===gemId){
    const pts=10*combo; score+=pts; hits++;
    power=Math.min(100,power+13);
    hole.classList.add('whacked'); setTimeout(()=>hole.classList.remove('whacked'),380);
    spawnGemBurst(cx,cy,combo); showPop(cx,cy,'+'+pts+' 💎','#f59e0b',22);
    sfx('hit'); hideChar(id); gemId=null; schedGem();
    combo=Math.min(combo+1,5); maxCombo=Math.max(maxCombo,combo);
    sfx('combo');
    updateComboUI(); updateScore(); updatePower(); checkFrenzy();

  } else if(id===moleId){
    score+=5; hits++;
    hole.classList.add('whacked'); setTimeout(()=>hole.classList.remove('whacked'),380);
    spawnGemBurst(cx,cy,1); showPop(cx,cy,'+5 🐭','#10b981',16);
    sfx('hit'); hideChar(id); moleId=null; schedMole(); updateScore();

  } else if(id===bombId){
    hole.classList.add('bombed');
    spawnMissBurst(cx,cy); spawnMissBurst(cx,cy);
    sfx('bomb'); showPop(cx,cy,'💣 BOOM!','#ef4444',22);
    screenShake(); setTimeout(()=>endGame(true),380);

  } else {
    spawnMissBurst(cx,cy); showPop(cx,cy,'MISS!','#ef4444',14);
    hole.classList.add('missed'); setTimeout(()=>hole.classList.remove('missed'),320);
    sfx('miss'); dropCombo();
  }
}

/* ===== COMBO ===== */
function dropCombo(){
  if(combo>1){ combo=1; updateComboUI(); showPop(window.innerWidth/2,180,'COMBO LOST!','#ef4444',12); }
}

function updateComboUI(){
  const el=$('combo-val');
  el.textContent='x'+combo;
  el.classList.remove('bump'); void el.offsetWidth; el.classList.add('bump');
  const labels=['','','🔥 DOUBLE!','💥 TRIPLE!','⚡ ULTRA COMBO!','👑 MAX COMBO!!'];
  const cd=$('combo-display');
  cd.textContent=combo>=2?(labels[combo]||'MAX!'):'';
  if(combo>=2){cd.classList.remove('shake');void cd.offsetWidth;cd.classList.add('shake');}
}

/* ===== POWER / FRENZY ===== */
function updatePower(){
  $('power-fill').style.width=power+'%';
  $('power-pct').textContent=power+'%';
  if(power>=100)$('power-fill').classList.add('maxed');
  else $('power-fill').classList.remove('maxed');
}

function checkFrenzy(){
  if(power>=100&&!powerMode){
    powerMode=true; power=0; updatePower();
    spawnFrenzyBurst(); sfx('frenzy');
    $('frenzy-flash').classList.add('active');
    showPop(window.innerWidth/2,window.innerHeight*.38,'💎 CRYSTAL FRENZY! +10s','#a855f7',20);
    timeLeft=Math.min(timeLeft+10,cfg.timeLimit+15);
    clearTimeout(powerModeTimer);
    powerModeTimer=setTimeout(()=>{powerMode=false;$('frenzy-flash').classList.remove('active');},8500);
  }
}

/* ===== SCORE POP ===== */
function updateScore(){
  const el=$('score-val'); el.textContent=score;
  el.classList.remove('bump'); void el.offsetWidth; el.classList.add('bump');
}

function showPop(x,y,text,color,size=18){
  const el=document.createElement('div');
  el.className='score-pop';
  el.style.cssText=`left:${x-40}px;top:${y-20}px;font-size:${size}px;color:${color};`;
  el.textContent=text;
  document.body.appendChild(el);
  setTimeout(()=>el.remove(),1100);
}

/* ===== SCREEN SHAKE ===== */
function screenShake(){
  const b=document.querySelector('.board-perspective');
  if(!b) return;
  b.animate([
    {transform:'translateX(-10px) translateY(5px)'},
    {transform:'translateX(10px) translateY(-5px)'},
    {transform:'translateX(-7px) translateY(3px)'},
    {transform:'translateX(7px) translateY(-3px)'},
    {transform:'translateX(-3px)'},
    {transform:'translateX(0)'},
  ],{duration:380,easing:'ease-out'});
}

/* ===== TIMER ===== */
const CIRC=219.9;
function startTimer(){
  clearInterval(timerInt);
  const max=cfg.timeLimit;
  const arc=$('arc-fill'), num=$('timer-val');
  timerInt=setInterval(()=>{
    if(!gameActive){clearInterval(timerInt);return;}
    timeLeft--;
    num.textContent=timeLeft;
    arc.style.strokeDashoffset=CIRC*(1-timeLeft/max);
    if(timeLeft<=5){ arc.style.stroke='url(#arcRed)'; num.classList.add('danger'); screenShake(); }
    if(timeLeft<=0) endGame(false);
  },1000);
}

/* ===== DIFF BUTTONS ===== */
function setupDiff(){
  document.querySelectorAll('.diff-btn').forEach(btn=>{
    btn.addEventListener('click',()=>{
      document.querySelectorAll('.diff-btn').forEach(b=>b.classList.remove('active'));
      btn.classList.add('active'); currentDiff=btn.dataset.diff;
    });
  });
}

/* ===== START ===== */
function startGame(){
  cfg=DIFF[currentDiff];
  score=0;combo=1;maxCombo=1;hits=0;totalClicks=0;power=0;powerMode=false;
  timeLeft=cfg.timeLimit; gameActive=true;
  gemId=null;moleId=null;bombId=null;
  clearTimeout(gemTimer);clearTimeout(moleTimer);clearTimeout(bombTimer);
  clearTimeout(powerModeTimer);clearInterval(timerInt);

  $('score-val').textContent='0';
  $('combo-val').textContent='x1';
  $('combo-display').textContent='';
  $('timer-val').textContent=timeLeft;
  $('timer-val').classList.remove('danger');
  $('arc-fill').style.strokeDashoffset='0';
  $('arc-fill').style.stroke='url(#arcGrad)';
  $('power-fill').style.width='0%';
  $('power-pct').textContent='0%';
  $('power-fill').classList.remove('maxed');
  $('frenzy-flash').classList.remove('active');
  $('diff-indicator').textContent=cfg.label;

  $('start-screen').classList.add('hidden');
  $('gameover-screen').classList.add('hidden');

  buildBoard(); initAudio(); startTimer();
  schedGem(); schedMole(); schedBomb();
  spawnFrenzyBurst();
}

/* ===== END ===== */
function endGame(bombed){
  gameActive=false;
  clearInterval(timerInt);
  clearTimeout(gemTimer);clearTimeout(moleTimer);clearTimeout(bombTimer);clearTimeout(powerModeTimer);
  $('frenzy-flash').classList.remove('active');
  [gemId,moleId,bombId].filter(x=>x!==null).forEach(id=>hideChar(id));
  gemId=null;moleId=null;bombId=null;
  sfx('gameover');
  bestScore=Math.max(bestScore,score);
  const acc=totalClicks>0?Math.round((hits/totalClicks)*100)+'%':'0%';
  let titleTxt="TIME'S UP!", g=GRADES.find(x=>score>=x.min)||GRADES[GRADES.length-1];
  if(bombed){titleTxt='💣 BOOM!';g={grade:'💥 Blown Up!',msg:'You hit a bomb! Stay sharp next time.'};}
  $('go-title').textContent=titleTxt;
  $('go-score').textContent=score;
  $('go-grade').textContent=g.grade;
  $('go-msg').textContent=g.msg;
  $('go-best').textContent=bestScore;
  $('go-combo').textContent='x'+maxCombo;
  $('go-hits').textContent=hits;
  $('go-acc').textContent=acc;
  setTimeout(()=>{$('gameover-screen').classList.remove('hidden');spawnFrenzyBurst();},bombed?300:550);
}

/* ===== MUSIC TOGGLE ===== */
function toggleMusic(){
  initAudio(); musicEnabled=!musicEnabled;
  const btn=$('music-toggle');
  if(musicEnabled){
    if(musicGain) musicGain.gain.value=.20;
    btn.textContent='🔊'; startMusic();
  } else {
    if(musicGain) musicGain.gain.value=0;
    btn.textContent='🔇'; stopMusic();
  }
}

/* ===== MAIN LOOP ===== */
function loop(t){ drawBg(t); tickParticles(); requestAnimationFrame(loop); }

/* ===== INIT ===== */
window.addEventListener('resize',()=>{resizeBg();resizeP();});
document.addEventListener('pointerdown',initAudio,{once:true});

$('play-btn').addEventListener('click',()=>{initAudio();startGame();});
$('retry-btn').addEventListener('click',()=>{initAudio();startGame();});
$('menu-btn').addEventListener('click',()=>{$('gameover-screen').classList.add('hidden');$('start-screen').classList.remove('hidden');});
$('music-toggle').addEventListener('click',toggleMusic);

setImages();
setupDiff();
initBg(); resizeP(); buildBoard();
initLoadingParticles();
runLoadingScreen();
requestAnimationFrame(loop);
